// AUTO-GENERATED by workflow — art. Do not hand-edit; re-run integrate.mjs.
// ENHANCED EDITION (art_v2): Talent icons 天賦圖示.
// Crisp, glowing talent glyphs with a committed top-left light source, neon /
// aurora / sakura accent trims, soft radial glows, "kira" star sparkles and a
// rim-light pass before the panel's auto outline. Every original defineIcon
// name + the panel background colour is preserved 1:1 (asset-key contract).
// The defineIcon helper draws panel(bg) -> draw(p) -> outline(P.ink), so we add
// p.rimLight() at the END of each draw body (before the helper's outline runs).
import { defineSprite, defineAnim, Painter } from '../../engine/sprites.js';
import { P, lighten, darken, mix, withAlpha } from '../../engine/palette.js';
import { defineIcon, panel, sym } from '../icons.js';
import { drawSlime, drawBat, drawWisp, drawBrute, drawHunter } from '../core.js';

// ── local helpers (additive) ───────────────────────────────────────────────
// A faint glowing aura behind a talent glyph + a couple of corner kira sparkles
// to give every icon that "powered-up" anime sheen. Kept tiny & crisp.
function talentGlow(p, col, r = 6, strength = 0.32) {
  p.glow(8, 8, r, col, strength, 4);
}
function cornerKira(p, col = P.glint) {
  p.star4(3, 3, 2, withAlpha(col, 0.9), col);
  p.star4(13, 13, 2, withAlpha(col, 0.55), col);
}

// ===== Talents 天賦圖示 (defineIcon) =====

// offense row0: 利刃 - 增加傷害
defineIcon("talent_g_keenedge", P.red, (p)=>{
  // 紅色刀刃 + 鋒利高光 — crimson laser-honed blade with motion sheen.
  talentGlow(p, P.laser, 6, 0.30);
  // slash motion streak behind the blade
  p.line(3, 12, 12, 3, withAlpha(P.redL, 0.5));
  p.line(2, 12, 11, 3, withAlpha(P.laser, 0.35));
  sym.sword(p);
  // recolour the steel blade into a glowing crimson edge
  p.replace(P.steel, P.redL);
  p.replace(P.steelL, P.white);
  // forge-bright edge gradient down the blade spine
  p.px(4, 9, P.white);
  p.px(5, 8, lighten(P.redL, 0.4));
  p.px(6, 7, P.redL);
  // 鋒利光點 — specular flash at the tip
  p.px(11, 3, P.white);
  p.px(12, 4, lighten(P.redL, 0.4));
  p.sparkle(8, 2, P.rim, 1);
  cornerKira(p, P.laser);
  p.rimLight(P.rim, 0.5);
});

